+        components: vec![ScoreComponent {
+            source: ExplainedSource::SemanticQuality {
+                embedder: "all-MiniLM-L6-v2".to_owned(),
+                cosine_sim: 0.92,
+            },
+            raw_score: 0.92,
+            normalized_score: 0.87,
+            rrf_contribution: 0.014,
+            weight: 0.7,
+        }],
+    };
+    
+    assert_golden_json("hit_explanation_v1", &explanation);
+}

